            ['name' => 'Fransız Dili og Edebiyatı', 'desc' => 'Fransızca dilinin yapısını, tarihsel değişimini ve Fransız kültürünün dünya edebiyatına yön veren eserlerini akademik ve eleştirel bir bakış açısıyla inceler.'],
            ['name' => 'Fransızca Mütercim ve Tercümanlık', 'desc' => 'Fransızca ve Türkçe dilleri arasında; yazılı metinlerin çevirisi ve sözlü iletişim süreçlerinde profesyonel düzeyde köprü kuracak uzmanlar yetiştirir.'],
            ['name' => 'Fransızca Öğretmenliği', 'desc' => 'Fransızca dilini هر yaş grubuna etkili yöntemlerle öğretmek üzere; dil yetkinliği, sınıf yönetimi ve eğitim psikolojisi üzerine uzmanlık kazandırır.'],
            ['name' => 'Gastronomi ve Mutfak Sanatları', 'desc' => 'Yemek pişirme tekniklerini، gıda bilimini ve mutfak yönetimini birleştiren; yemek kültürünü sanatsal bir estetik ve profesyonel işletmecilik anlayışıyla ele alan bölümdür.'],
            ['name' => 'Gazetecilik', 'desc' => 'Güncel olayları araştırma، haber değeri taşıyan içerikleri toplama، yazma ve dijital/yazılı medya kanalları aracılığıyla topluma etik kurallar çerçevesinde aktarma sürecidir.'],
            ['name' => 'Geleneksel Türk Sanatları', 'desc' => 'Hat, ebru, tezhip, çini, halı-kilim dokuma gibi köklü Türk kültür mirasına dayalı sanat dallarının tekniklerini öğreten ve bu değerleri modern tasarımlarla geleceğe taşıyan alandır.'],
            ['name' => 'Gayrimenkul Geliştirme ve Yönetimi', 'desc' => 'Arazi ve konut projelerinin finansal analizi، taşınmaz değerleme، gayrimenkul hukuku ve yatırım stratejileri üzerine odaklanan، ekonomi ve işletme temelli bir bölümdür.'],
            ['name' => 'Gemi İnşaatı ve Gemi Makineleri Mühendisliği', 'desc' => 'Her türlü deniz taşıtının tasarımı، gövde yapısı، stabilite hesapları ve içindeki makine sistemlerinin montajı/bakımı üzerine uzmanlaşan teknik mühendislik dalıdır.'],
            ['name' => 'Gemi Makineleri İşletme Mühendisliği', 'desc' => 'Gemilerin ana makinelerinin، yardımcı sistemlerinin ve elektrik devrelerinin çalıştırılması، bakımı ve onarımıyla ilgilenen uzmanlar yetiştiren bölümdür.'],
            ['name' => 'Gemi ve Deniz Teknolojisi Mühendisliği', 'desc' => 'Gemi inşaatının yanı sıra deniz altı yapıları، açık deniz platformları ve yenilenebilir deniz enerji sistemlerinin tasarımı ve üretimi üzerine uzmanlaşan mühendislik dalıdır.'],
            ['name' => 'Gemi ve Yat Tasarımı', 'desc' => 'Deniz araçlarının hem estetik görünümünü hem de iç mekan fonksiyonelliğini، mühendislik sınırları içerisinde tasarlayan sanat ve teknik odaklı bölümdür.'],
            ['name' => 'Genetik ve Biyomühendislik', 'desc' => 'Canlıların genetik yapısını analiz eden ve bu bilgileri mühendislik teknikleriyle birleştirerek yeni tedavi yöntemleri، ilaçlar veya tarımsal ürünler geliştiren bilim dalıdır.'],
            ['name' => 'Geomatik Mühendisliği (Harita Mühendisliği)', 'desc' => 'Yeryüzünün ölçülmesi، uydu görüntüleri ve GPS verileriyle haritalandırılması، coğrafi bilgi sistemlerinin yönetilmesi ve arazi planlaması süreçlerini kapsار.'],
            ['name' => 'Gerontoloji (Yaşlılık Bilimi)', 'desc' => 'Yaşlanmanın biyolojik، psikolojik ve sosyal boyutlarını inceleyen; yaşlı bireylerin yaşam kalitesini artıracak politikalar ve bakım modelleri geliştiren bilim dalıdır.'],
            ['name' => 'Gıda Mühendisliği', 'desc' => 'Tarımsal hammaddelerin güvenli، kaliteli ve uzun ömürlü gıda ürünlerine dönüştürülmesi için üretim süreçlerini، paketleme ve depolama tekniklerini tasarlayan daldır.'],
            ['name' => 'Görsel İletişim Tasarımı', 'desc' => 'Bilgiyi ve mesajı dijital mecralarda etkili bir şekilde aktarmak için grafik، tipografi ve etkileşimli öğeleri birleştiren tasarım dalıdır.'],
            ['name' => 'Görsel Sanatlar', 'desc' => 'Resim, heykel, seramik gibi geleneksel sanat dallarının yanı sıra modern sanat pratiklerini ve teorilerini kapsayan، yaratıcı ifadeye odaklanan bölümdür.'],
            ['name' => 'Grafik Tasarımı', 'desc' => 'Logo, afiş, kitap tasarımı gibi görsel unsurların; bir marka kimliği oluşturmak veya bir mesajı görsel yolla iletmek amacıyla estetik ve teknik kurallarla düzenlenmesi sanatıdır.'],
            ['name' => 'Halkla İlişkiler ve Reklamcılık', 'desc' => 'Bir kurumun veya markanın itibarını yönetme، hedef kitleyle stratejik iletişim kurma ve ürün/hizmetleri tanıtmak için yaratıcı kampanyalar yürütme alanıdır.'],
            ['name' => 'Girişimcilik', 'desc' => 'Yeni iş fikirleri geliştirme، risk yönetimi، pazar analizi ve yenilikçi iş modelleri kurma süreçlerini öğreterek liderler yetiştirir.'],
            ['name' => 'Gümrük İşletme', 'desc' => 'Uluslararası ticaret hukukuna uygun olarak malların gümrüklerden geçiş işlemlerini، vergilendirme süreçlerini ve dış ticaret lojistiğini yöneten uzmanlık alanıdır.'],
            ['name' => 'Halkla İlişkiler ve Tanıtım', 'desc' => 'Bir kurum veya markanın kamuoyundaki imajını yöneten، hedef kitleyle stratejik iletişim kuran ve tanıtım faaliyetlerini organize eden bölümdür.'],
            ['name' => 'Havacılık Elektrik ve Elektroniği', 'desc' => 'Hava araçlarının uçuş kontrol، seyrüsefer، haberleşme ve güç sistemleri gibi elektronik aksamlarının bakımı ve tasarımı üzerine odaklanır.'],
            ['name' => 'Havacılık ve Uzay Mühendisliği', 'desc' => 'Uçak، helikopter gibi hava araçları ile uydu ve roket gibi uzay araçlarının tasarımını، üretimini ve test süreçlerini yöneten mühendislik dalıdır.'],
            ['name' => 'Havacılık Yönetimi', 'desc' => 'Havayolu şirketleri ve havalimanlarının işletilmesi، uçuş planlaması، lojistik ve sivil havacılık operasyonlarının idari süreçlerini konu alır.'],
            ['name' => 'Hayvansal Üretim ve Teknolojileri', 'desc' => 'Büyükbaş، küçükbaş ve kümes hayvanlarının ıslahı، beslenmesi ve hayvansal ürünlerin verimli şekilde elde edilmesi için modern teknolojiler geliştiren alandır.'],
            ['name' => 'Hemşirelik', 'desc' => 'Bireylerin sağlığını koruma، hastalık sürecinde tıbbi bakım sağlama ve doktor tarafından planlanan tedavileri uygulama üzerine uzmanlaşan sağlık bilimidir.'],
            ['name' => 'Hidrojeoloji Mühendisliği', 'desc' => 'Yer altı sularının oluşumu، hareketi، kalitesi ve bu kaynakların çevreyle olan etkileşimini mühendislik yöntemleriyle inceleyen daldır.'],
            ['name' => 'Hukuk', 'desc' => 'Adalet sistemini، toplumsal düzeni sağlayan yasaları، bu yasaların uygulanmasını ve bireyler/kurumlar arasındaki hukuki uyuşmazlıkların çözümünü inceleyen disiplindir.'],
            ['name' => 'İç Mimarlık', 'desc' => 'Bina içindeki mekanların estetik، işlevsel ve kullanıcı ihtiyaçlarına uygun şekilde tasarlanması ve dekorasyon süreçlerini yöneten bölümdür.'],
            ['name' => 'İç Mimarlık ve Çevre Tasarımı', 'desc' => 'Mekan tasarımını fiziksel çevreyle bütünleştiren; malzeme، aydınlatma ve kullanıcı konforunu çevresel bağlamıyla birlikte ele alan uzmanlık alanıdır.'],
            ['name' => 'İlahiyat', 'desc' => 'İslam dininin temel kaynaklarını، inanç sistemini، tarihini ve dini bilimleri akademik bir perspektifle araştıran ve inceleyen bölümdür.'],
            ['name' => 'İletişim', 'desc' => 'Bilgi، duygu ve düşüncelerin farklı kanallar aracılığıyla hedef kitleye aktارılması süreçlerini kapsayan geniş bir alandır.'],
            ['name' => 'İletişim Bilimleri', 'desc' => 'İletişim süreçlerinin toplumsal، psikolojik ve kültürel etkilerini teorik modeller ve araştırmalar üzerinden inceleyen akademik disiplindir.'],
            ['name' => 'İletişim Sanatları', 'desc' => 'Reklamcılık، halkla ilişkiler ve görsel sanatları birleştirerek، markalar veya kurumlar için yaratıcı iletişim stratejileri ve içerikleri geliştiren bölümdür.'],
            ['name' => 'İletişim Tasarımı ve Yönetimi', 'desc' => 'Tasarım odaklı düşünmeyi، kurumsal iletişim stratejileri ve medya projelerinin yönetim süreçleriyle birleştiren disiplindir.'],
            ['name' => 'İletişim ve Tasarımı', 'desc' => 'Bir mesajın dijital ve görsel platformlarda en etkili ve estetik şekilde sunulması için gerekli teknik ve teorik altyapıyı sağlar.'],
